few_shot_examples.plantuml:
@startuml
class Book {
  +String title
  +String isbn
  +String author
  +getTitle()
  +getISBN()
}

class Member {
  +String name
  +String memberId
  +getName()
}

class Loan {
  +Date borrowDate
  +Date returnDate
  +getBorrowDate()
  +getReturnDate()
}

Member "1" -- "*" Loan : places
Book "1" -- "*" Loan : borrowed_in
@enduml

@startuml
class Customer {
  +String email
  +String shippingAddress
  +placeOrder()
}

class Order {
  +int orderId
  +Date orderDate
  +getTotal()
}

class OrderItem {
  +int quantity
  +float price
  +getSubtotal()
}

class Product {
  +String name
  +float price
  +String sku
  +getName()
  +getPrice()
}

Customer "1" -- "*" Order : places
Order "1" -- "*" OrderItem : contains
Product "1" -- "*" OrderItem : referenced_by
@enduml

@startuml
class Student {
  +String studentId
  +String name
  +String email
  +enroll()
}

class Course {
  +String courseCode
  +String title
  +int credits
  +getTitle()
}

class Enrollment {
  +String grade
  +getGrade()
}

Student "1" -- "*" Enrollment : has
Course "1" -- "*" Enrollment : enrolled_in
@enduml
